class Solution {
    public int hardestWorker(int n, int[][] logs) {
        int maxTime = 0;
        int result = Integer.MAX_VALUE;
        int prevTime = 0;
        for (int[] log : logs) {
            int id = log[0];
            int leaveTime = log[1];
            int time = leaveTime - prevTime;
            prevTime = leaveTime;
            if (time > maxTime) {
                maxTime = time;
                result = id;
            } else if (time == maxTime) {
                result = Math.min(result, id);
            }
        }
        return result;
    }
}
